import numpy as np

def solvent_effect(charges_reactant, charges_ts, radii, epsilon):
    """
    Estimate solvent effect on activation energy.
    """
    # Born solvation constant
    # dG_solv = -332 * q^2 / (2*r) * (1 - 1/epsilon) kcal/mol
    born_factor = 332.0 / 2  # 166 kcal*A/mol

    def calc_solvation(charges, radii, eps):
        dG = 0
        for q, r in zip(charges, radii):
            if r > 0:
                dG += -born_factor * (q**2) / r * (1 - 1/eps)
        return dG

    dG_reactant = calc_solvation(charges_reactant, radii, epsilon)
    dG_ts = calc_solvation(charges_ts, radii, epsilon)

    delta_delta_G = dG_ts - dG_reactant

    if delta_delta_G < -0.5:
        prediction = 'faster (TS more stabilized)'
    elif delta_delta_G > 0.5:
        prediction = 'slower (reactant more stabilized)'
    else:
        prediction = 'similar rate'

    return {
        'dG_solv_reactant': dG_reactant,
        'dG_solv_ts': dG_ts,
        'delta_delta_G': delta_delta_G,
        'prediction': prediction,
        'epsilon': epsilon
    }
